from math import gcd
import itertools

class Solution:
    def minOperations(self, nums):
        n = len(nums)
        ones = sum(1 for v in nums if v == 1)
        if ones > 0:
            return n - ones
        overall = 0
        for v in nums:
            overall = gcd(overall, v)
        if overall != 1:
            return -1
        best = None
        for start in range(n):
            prefix_gcds = itertools.accumulate(nums[start:], gcd)
            for offset, g in enumerate(prefix_gcds):
                if g == 1:
                    length = offset + 1
                    if best is None or length < best:
                        best = length
                    break
        return (best - 1) + (n - 1)

