from math import gcd

class Solution:
    def minOperations(self, nums):
        n = len(nums)
        ones = nums.count(1)
        if ones > 0:
            return n - ones
        g = 0
        for v in nums:
            g = gcd(g, v)
        if g != 1:
            return -1
        min_len = float('inf')
        for i in range(n):
            cur = nums[i]
            for j in range(i + 1, n):
                cur = gcd(cur, nums[j])
                if cur == 1:
                    min_len = min(min_len, j - i + 1)
                    break
        return (min_len - 1) + (n - 1)

