function gcdPair(a, b) {
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}

var minOperations = function(nums) {
    const n = nums.length;
    const ones = nums.filter((v) => v === 1).length;
    if (ones > 0) return n - ones;
    let g = 0;
    for (const v of nums) g = gcdPair(g, v);
    if (g !== 1) return -1;
    let minLen = Infinity;
    for (let i = 0; i < n; i++) {
        let cur = nums[i];
        for (let j = i + 1; j < n; j++) {
            cur = gcdPair(cur, nums[j]);
            if (cur === 1) {
                minLen = Math.min(minLen, j - i + 1);
                break;
            }
        }
    }
    return (minLen - 1) + (n - 1);
};
